def _sbsfc078_route(operation_kind, canonical_name):
    if operation_kind == "signal":
        return ("general.signal_diagnostic", "SBLR_GENERAL_SIGNAL_DIAGNOSTIC", "EngineSignalDiagnostic", "diagnostic_signal")
    if operation_kind == "raise":
        return ("general.raise_diagnostic", "SBLR_GENERAL_RAISE_DIAGNOSTIC", "EngineRaiseDiagnostic", "diagnostic_raise")
    if operation_kind == "resignal":
        return ("general.resignal_diagnostic", "SBLR_GENERAL_RESIGNAL_DIAGNOSTIC", "EngineResignalDiagnostic", "diagnostic_resignal")
    return ("general.procedural_operation", "SBLR_GENERAL_PROCEDURAL_OPERATION", "EngineGeneralProceduralOperation", "procedural_general_route")


