def cluster_provider_contract_note(notes: str) -> str:
    normalized = (
        notes
        .replace("no engine ABI dispatch", "no direct open-core private-cluster executor dispatch")
        .replace("no engine ABI", "no direct open-core private-cluster executor")
        .replace("does not reach the engine ABI", "does not reach any direct open-core private-cluster executor")
        .replace("public dispatch refuses before cluster execution", "the default/open-core provider path returns unsupported before private cluster execution")
        .replace("public refusal before cluster execution", "default/open-core provider unsupported response before private cluster execution")
    )
    return (
        f"{normalized} Build-mode contract: default/open-core builds route through the no-cluster "
        "provider and must return SBLR.CLUSTER.SUPPORT_NOT_ENABLED; cluster-enabled builds route "
        "through the separate cluster provider target and must return the row-identifiable "
        "cluster.provider.stub.v1/SBLR.CLUSTER.STUB_RESPONSE response until the private provider is linked."
    )

