def fail(message: str) -> None:
    print(message, file=sys.stderr)
    raise SystemExit(1)


def escape_control_chars(value: str) -> str:
    rendered = []
    for char in value:
        codepoint = ord(char)
        if codepoint < 0x20 or codepoint == 0x7F:
            rendered.append(f"\\u{codepoint:04x}")
        else:
            rendered.append(char)
    return "".join(rendered)


def sanitize_output_row(row: dict[str, str], columns: list[str]) -> dict[str, str]:
    return {column: escape_control_chars(str(row.get(column, ""))) for column in columns}


def read_csv(path: Path) -> list[dict[str, str]]:
    if not path.is_file():
        fail(f"required CSV missing: {path}")
    with path.open(newline="", encoding="utf-8") as handle:
        return list(csv.DictReader(handle))


def index_by(rows: list[dict[str, str]], key: str, label: str) -> dict[str, dict[str, str]]:
    out: dict[str, dict[str, str]] = {}
    for row in rows:
        value = row.get(key, "")
        if not value:
            fail(f"{label} row missing {key}")
        if value in out:
            fail(f"{label} duplicate {key}: {value}")
        out[value] = row
    return out


def index_oracle_by_builtin(rows: list[dict[str, str]]) -> dict[str, dict[str, str]]:
    out: dict[str, dict[str, str]] = {}
    for row in rows:
        builtin_id = row.get("matched_builtin_id", "")
        if not builtin_id:
            continue
        if not builtin_id.startswith("sb.scalar."):
            continue
        existing = out.get(builtin_id)
        if existing is not None:
            for key in ("sblr_binding", "engine_entrypoint"):
                if existing.get(key, "") != row.get(key, ""):
                    fail(f"FUNCTION_SEMANTIC_ORACLE_MATRIX inconsistent {builtin_id} field {key}")
            if existing.get("oracle_authority_status") != "full_oracle" and row.get("oracle_authority_status") == "full_oracle":
                out[builtin_id] = row
            continue
        out[builtin_id] = row
    return out


def index_full_oracle_by_builtin(rows: list[dict[str, str]]) -> dict[str, dict[str, str]]:
    out: dict[str, dict[str, str]] = {}
    for row in rows:
        if row.get("oracle_authority_status") != "full_oracle":
            continue
        builtin_id = row.get("matched_builtin_id", "")
        if not builtin_id.startswith("sb."):
            continue
        existing = out.get(builtin_id)
        if existing is not None:
            for key in ("oracle_authority_status", "sblr_binding", "engine_entrypoint"):
                if existing.get(key, "") != row.get(key, ""):
                    fail(f"FUNCTION_SEMANTIC_ORACLE_MATRIX inconsistent full oracle {builtin_id} field {key}")
            continue
        out[builtin_id] = row
    return out


def sbsfc013_expected_proof(row: dict[str, str]) -> str:
    if row["expected_diagnostic_code"]:
        return f"expected_diagnostic={row['expected_diagnostic_code']}"
    return (
        f"expected_result={row['expected_result_value']};"
        f"descriptor={row['expected_result_descriptor']}"
    )


