def sbsfc012_temporal_session_expected_proof(row: dict[str, str]) -> str:
    if row["expected_diagnostic_code"]:
        return f"expected_diagnostic={row['expected_diagnostic_code']}"
    if row["expected_result_value"]:
        return (
            f"expected_result={row['expected_result_value']};"
            f"descriptor={row['expected_result_descriptor']}"
        )
    if row.get("case_kind") == "null_strict":
        return f"expected_null;descriptor={row['expected_result_descriptor']}"
    return f"descriptor={row['expected_result_descriptor']};case_kind={row.get('case_kind', '')}"


def index_sbsfc012_temporal_session_provider_field_arithmetic_fixture_rows(
    rows: list[dict[str, str]]
) -> dict[str, dict[str, str]]:
    grouped: dict[str, dict[str, str]] = {}
    proofs_by_id: dict[str, list[str]] = {}
    fixture_ids_by_id: dict[str, list[str]] = {}
    for row in rows:
        surface_id = row.get("surface_id", "")
        if surface_id not in SBSFC012_TEMPORAL_SESSION_PROVIDER_FIELD_ARITHMETIC_SURFACE_IDS:
            continue
        if row.get("function_id") != row.get("canonical_builtin_id"):
            fail(f"SBSFC_012_TEMPORAL_SESSION_FIXTURES {surface_id} function/builtin id drift")
        if surface_id in grouped:
            baseline = grouped[surface_id]
            for key in ("function_id", "canonical_builtin_id", "expected_result_descriptor"):
                if baseline[key] != row[key]:
                    fail(f"SBSFC_012_TEMPORAL_SESSION_FIXTURES inconsistent duplicate {surface_id} field {key}")
        else:
            grouped[surface_id] = dict(row)
            proofs_by_id[surface_id] = []
            fixture_ids_by_id[surface_id] = []
        fixture_ids_by_id[surface_id].append(row["fixture_id"])
        proofs_by_id[surface_id].append(f"{row['fixture_id']}:{sbsfc012_temporal_session_expected_proof(row)}")

    for surface_id, row in grouped.items():
        row["fixture_id"] = "+".join(fixture_ids_by_id[surface_id])
        row["expected_evidence"] = "+".join(proofs_by_id[surface_id])
    return grouped


def index_sbsfc010_numeric_fixture_rows(rows: list[dict[str, str]]) -> dict[str, dict[str, str]]:
    if len(rows) != SBSFC010_NUMERIC_SCALAR_EXPECTED_FIXTURE_ROW_COUNT:
        fail(
            "SBSFC_010_NUMERIC_BUILTIN_FIXTURES fixture row count changed: "
            f"expected {SBSFC010_NUMERIC_SCALAR_EXPECTED_FIXTURE_ROW_COUNT}, observed {len(rows)}"
        )

    grouped: dict[str, dict[str, str]] = {}
    proofs_by_id: dict[str, list[str]] = {}
    fixture_ids_by_id: dict[str, list[str]] = {}
    for row in rows:
        surface_id = row.get("surface_id", "")
        if not surface_id:
            fail("SBSFC_010_NUMERIC_BUILTIN_FIXTURES row missing surface_id")
        if row.get("function_id") != row.get("canonical_builtin_id"):
            fail(f"SBSFC_010_NUMERIC_BUILTIN_FIXTURES {surface_id} function/builtin id drift")
        if surface_id in grouped:
            baseline = grouped[surface_id]
            for key in ("function_id", "canonical_builtin_id", "expected_result_descriptor"):
                if baseline[key] != row[key]:
                    fail(f"SBSFC_010_NUMERIC_BUILTIN_FIXTURES inconsistent duplicate {surface_id} field {key}")
        else:
            grouped[surface_id] = dict(row)
            proofs_by_id[surface_id] = []
            fixture_ids_by_id[surface_id] = []
        fixture_ids_by_id[surface_id].append(row["fixture_id"])
        proofs_by_id[surface_id].append(f"{row['fixture_id']}:{sbsfc010_numeric_expected_proof(row)}")

    surface_ids = sorted(grouped)
    observed_digest = hashlib.sha256("\n".join(surface_ids).encode("utf-8")).hexdigest()
    if len(surface_ids) != SBSFC010_NUMERIC_SCALAR_EXPECTED_SURFACE_COUNT:
        fail(
            "SBSFC_010_NUMERIC_BUILTIN_FIXTURES surface_id count changed: "
            f"expected {SBSFC010_NUMERIC_SCALAR_EXPECTED_SURFACE_COUNT}, observed {len(surface_ids)}"
        )
    if observed_digest != SBSFC010_NUMERIC_SCALAR_EXPECTED_SURFACE_ID_DIGEST:
        fail("SBSFC_010_NUMERIC_BUILTIN_FIXTURES surface_id set changed unexpectedly")

    for surface_id, row in grouped.items():
        row["fixture_id"] = "+".join(fixture_ids_by_id[surface_id])
        row["expected_evidence"] = "+".join(proofs_by_id[surface_id])
    return grouped


