def index_sbsfc015_population_aggregate_fixture_rows(rows: list[dict[str, str]]) -> dict[str, dict[str, str]]:
    grouped: dict[str, dict[str, str]] = {}
    for row in rows:
        surface_id = row.get("surface_id", "")
        if surface_id not in SBSFC015_POPULATION_AGGREGATE_SURFACE_IDS:
            continue
        if surface_id in grouped:
            fail(f"SBSFC_015_AGGREGATE_WINDOW_FIXTURES duplicate population aggregate surface_id: {surface_id}")
        if row.get("evaluation_mode") != "aggregate":
            fail(f"SBSFC_015_AGGREGATE_WINDOW_FIXTURES {surface_id} requires aggregate evaluation_mode")
        grouped[surface_id] = dict(row)
        grouped[surface_id]["expected_evidence"] = (
            f"{row['fixture_id']}:{sbsfc015_aggregate_expected_proof(row)}"
        )
    return grouped


def index_sbsfc015_listagg_aggregate_fixture_rows(rows: list[dict[str, str]]) -> dict[str, dict[str, str]]:
    grouped: dict[str, dict[str, str]] = {}
    proofs_by_id: dict[str, list[str]] = {}
    fixture_ids_by_id: dict[str, list[str]] = {}
    observed_fixture_ids: set[str] = set()
    for row in rows:
        fixture_id = row.get("fixture_id", "")
        if fixture_id not in SBSFC015_LISTAGG_FIXTURE_IDS:
            continue
        observed_fixture_ids.add(fixture_id)
        surface_id = row.get("surface_id", "")
        if surface_id not in SBSFC015_LISTAGG_AGGREGATE_SURFACE_IDS:
            fail(f"SBSFC_015_AGGREGATE_WINDOW_FIXTURES unexpected LISTAGG surface_id: {surface_id}")
        if row.get("canonical_builtin_id") != "sb.aggregate.listagg":
            fail(f"SBSFC_015_AGGREGATE_WINDOW_FIXTURES {surface_id} LISTAGG builtin id drift")
        if row.get("evaluation_mode") != "aggregate":
            fail(f"SBSFC_015_AGGREGATE_WINDOW_FIXTURES {surface_id} LISTAGG requires aggregate evaluation_mode")
        if surface_id in grouped:
            baseline = grouped[surface_id]
            for key in ("function_id", "canonical_builtin_id", "expected_result_descriptor"):
                if baseline[key] != row[key]:
                    fail(f"SBSFC_015_AGGREGATE_WINDOW_FIXTURES inconsistent LISTAGG duplicate {surface_id} field {key}")
        else:
            grouped[surface_id] = dict(row)
            proofs_by_id[surface_id] = []
            fixture_ids_by_id[surface_id] = []
        fixture_ids_by_id[surface_id].append(fixture_id)
        proofs_by_id[surface_id].append(f"{fixture_id}:{sbsfc015_aggregate_expected_proof(row)}")

    if observed_fixture_ids != SBSFC015_LISTAGG_FIXTURE_IDS:
        fail("SBSFC_015_AGGREGATE_WINDOW_FIXTURES LISTAGG fixture set does not match SBSFC-015R-B override")
    for surface_id, row in grouped.items():
        row["fixture_id"] = "+".join(fixture_ids_by_id[surface_id])
        row["expected_evidence"] = "+".join(proofs_by_id[surface_id])
    return grouped


